def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        power_terms = []
        for j in range(1, 20):
            if j % 5 == 0:
                factor = 1.5
            elif j % 4 == 0:
                factor = 1.3
            elif j % 3 == 0:
                factor = 1.1
            elif j % 2 == 0:
                factor = 0.9
            else:
                factor = 0.7
            term = factor * (1 / (j**1.8)) * (ratio ** j)
            power_terms.append(term)
        score = sum(power_terms)
        remaining = capacity - item
        if remaining < 0.025 * capacity:
            score *= 3
        elif remaining < 0.07 * capacity:
            score *= 2
        elif remaining < 0.15 * capacity:
            score *= 1.3
        elif remaining < 0.3 * capacity:
            score *= 1.05
        else:
            score *= 0.85
        mods = [int(capacity) % x == 0 for x in [2,3,5,7,11]]
        mod2, mod3, mod5, mod7, mod11 = mods
        if mod3 and mod5 and mod7:
            score -= 0.2 * (capacity / 12)
        elif mod5 and mod7 and mod11:
            score -= 0.25 * (capacity / 18)
        elif mod2 and mod3 and mod5:
            score -= 0.15 * (capacity / 10)
        elif mod3 and mod7:
            score -= 0.12 * (capacity / 22)
        elif mod5 and mod11:
            score -= 0.18 * (capacity / 16)
        elif mod2 and mod11:
            score -= 0.1 * (capacity / 20)
        elif mod7:
            score -= 0.08 * (capacity / 30)
        else:
            score -= 0.04 * (capacity / 35)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.012 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 2 * threshold:
                penalty += 0.15 * k
            elif diff < 3 * threshold:
                penalty += 0.05 * k
            else:
                penalty -= 0.04 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 1.8:
            for m in range(1, 6):
                sub_capacity = capacity / m
                if abs(sub_capacity - item) < 0.025 * sub_capacity:
                    score *= (1 + 0.07 * m)
        extra_factor = 1
        for n in range(1, 5):
            if (int(capacity) + n) % 4 == 0:
                extra_factor *= 1 + 0.03 * n
            else:
                extra_factor *= 1 - 0.01 * n
        score *= extra_factor
        if ratio > 0.9:
            score += 0.1 * (1 - ratio) * 10
        elif ratio < 0.3:
            score *= 0.9
        priorities[i] = score
    return priorities
